    def minMovesToMakePalindrome(self, s: str) -> int:
        s = list(s)
        res = 0
        left, right = 0, len(s) - 1
        while left < right:
            if s[left] == s[right]:
                left += 1
                right -= 1
            else:
                mid = left + 1
                while mid < right and s[mid] != s[right]:
                    mid += 1
                if mid < right:
                    while mid > left:
                        s[mid], s[mid - 1] = s[mid - 1], s[mid]
                        mid -= 1
                        res += 1
                left += 1
                right -= 1
        return res
